/* DMA 循环缓冲区架构定义 —— 伪代码，展示接口分层 */

/* 第一层：缓冲区管理接口 */
typedef struct {
    uint8_t *buf;          /* 指向 DMA 缓冲区 */
    uint16_t size;         /* 缓冲区总大小 */
    volatile uint16_t head; /* 写指针（DMA 更新）*/
    uint16_t tail;         /* 读指针（CPU 更新）*/
} dma_ring_buf_t;

/* 第二层：DMA 初始化（硬件相关） */
void dma_ring_buf_init(dma_ring_buf_t *rb, uint8_t *mem, uint16_t sz);

/* 第三层：协议层使用（与 DMA 无关） */
int protocol_parse_frame(dma_ring_buf_t *rb, uint8_t *out, uint16_t max_len);

/* 使用示例 */
/* dma_ring_buf_t uart_rb; */
