#define UART_DMA_BUF_SIZE  256

/* DMA 循环缓冲区 —— 必须放在 DMA 可访问的内存段 */
uint8_t uart_dma_rx_buf[UART_DMA_BUF_SIZE] __attribute__((aligned(4)));

/* 非阻塞读取：从缓冲区取数据供上层使用 */
int uart_dma_poll(uint8_t *out, uint16_t max_len) {
    /* __HAL_DMA_GET_COUNTER 返回剩余字节数 */
    uint16_t remaining = __HAL_DMA_GET_COUNTER(&hdma_usart1_rx);
    uint16_t written = UART_DMA_BUF_SIZE - remaining;

    /* 无新数据 */
    if (written <= last_written) return 0;

    /* 计算可读字节数 */
    uint16_t avail = written - last_written;
    if (avail > max_len) avail = max_len;

    /* 复制数据（注意可能跨缓冲区边界） */
    uint16_t start = last_written % UART_DMA_BUF_SIZE;
    for (uint16_t i = 0; i < avail; i++) {
        out[i] = uart_dma_rx_buf[(start + i) % UART_DMA_BUF_SIZE];
    }

    last_written = written;
    return (int)avail;
}

/* 可选：DMA TC 回调，用于通知应用层有大批量数据到达 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    /* 这里只做标记，不做数据处理 —— 避免在中断里做耗时操作 */
    data_arrived_flag = 1;
}

/* 正确的 DMA2_Stream5 + USART1_RX 初始化（寄存器级） */
void uart_dma_init(void) {
    /* 使能 DMA2 时钟 */
    RCC->AHB1ENR |= RCC_AHB1ENR_DMA2EN;

    /* 配置 DMA2_Stream5：Peripheral→Memory, Circular, 8bit */
    DMA2_Stream5->CR  = DMA_SxCR_DIR_0;           /* PeriphToMemory */
    DMA2_Stream5->CR |= DMA_SxCR_CIRC;             /* Circular 模式 */
    DMA2_Stream5->CR &= ~DMA_SxCR_MINC;            /* MemoryInc = 1 (递增) */
    DMA2_Stream5->CR |= DMA_SxCR_PINC;             /* Pinc = 1 (外设地址固定) */
    DMA2_Stream5->CR &= ~(DMA_SxCR_PSIZE | DMA_SxCR_MSIZE); /* PSIZE=MSIZE=8bit */
    DMA2_Stream5->PAR  = (uint32_t)&USART1->RDR;   /* 外设数据寄存器地址 */
    DMA2_Stream5->NDTR = UART_DMA_BUF_SIZE;         /* 传输计数 */
    DMA2_Stream5->M0AR = (uint32_t)uart_dma_rx_buf; /* 内存缓冲区 */

    /* 开启 DMA TC 中断 */
    DMA2_Stream5->CR |= DMA_SxCR_TCIE;              /* TC 中断使能 */

    /* NVIC 配置：DMA2_Stream5 抢占优先级 = 2 */
    NVIC_SetPriority(DMA2_Stream5_IRQn, 2);
    NVIC_EnableIRQ(DMA2_Stream5_IRQn);

    /* 启动 DMA */
    DMA2_Stream5->CR |= DMA_SxCR_EN;                /* 使能 DMA */
}

/* 中断服务函数 —— 只清标志，不做数据处理 */
void DMA2_Stream5_IRQHandler(void) {
    if (DMA2->LISR & DMA_LISR_TCIF5) {
        DMA2->LIFCR = DMA_LIFCR_CTCIF5;             /* 清除 TC 标志 */
        /* 不要在这里清 USART1 的中断标志！那是另一回事 */
        data_ready = 1;                              /* 通知主循环 */
    }
}

/* ===== 重构前：中断逐字节接收（坏味道） ===== */
static uint8_t rx_buf[256];
static volatile uint16_t rx_idx = 0;

void USART1_IRQHandler(void) {
    if (USART1->SR & USART_SR_RXNE) {
        uint8_t byte = USART1->DR;          /* 每字节一次中断 */
        rx_buf[rx_idx++] = byte;            /* 无边界检查！ */
        if (rx_idx >= 256) rx_idx = 0;      /* 覆盖旧数据，静默丢失 */
        /* 没有通知机制，主循环不知道有新数据 */
    }
}

/* 主循环中轮询缓冲区 —— 不知道什么时候有数据 */
while(1) {
    if (rx_idx > 0) {
        parse_protocol(rx_buf, rx_idx);     /* 每次从头解析，效率低 */
    }
}

/* ===== 重构后：DMA 循环缓冲区（好结构） ===== */
#define RX_BUF_SIZE 256
static uint8_t dma_rx_buf[RX_BUF_SIZE];
static volatile uint16_t dma_head = 0;    /* DMA 写入位置 */
static uint16_t cpu_tail = 0;             /* CPU 读取位置 */
static volatile uint8_t  new_data = 0;    /* 通知标志 */

/* 初始化：配置 DMA2_Stream5 + USART1_RX 为 Circular 模式 */
void uart_dma_setup(void) {
    hdma_usart1_rx.Instance = DMA2_Stream5;
    hdma_usart1_rx.Init.Channel = DMA_CHANNEL_4;
    hdma_usart1_rx.Init.Direction = DMA_PERIPH_TO_MEMORY;
    hdma_usart1_rx.Init.PeriphInc = DMA_PINC_DISABLE;
    hdma_usart1_rx.Init.MemInc = DMA_MINC_ENABLE;
    hdma_usart1_rx.Init.PeriphDataAlignment = DMA_PDATAALIGN_BYTE;
    hdma_usart1_rx.Init.MemDataAlignment = DMA_MDATAALIGN_BYTE;
    hdma_usart1_rx.Init.Mode = DMA_CIRCULAR;  /* 关键：循环模式 */
    hdma_usart1_rx.Init.Priority = DMA_PRIORITY_HIGH;
    HAL_DMA_Init(&hdma_usart1_rx);
    __HAL_LINKDMA(&huart1, hdmarx, hdma_usart1_rx);
    HAL_NVIC_SetPriority(DMA2_Stream5_IRQn, 2, 0);
    HAL_NVIC_EnableIRQ(DMA2_Stream5_IRQn);
}

/* DMA TC 回调：只设标志，不处理数据 */
void HAL_UARTEx_RxEventCallback(UART_HandleTypeDef *huart, uint16_t size) {
    new_data = 1;  /* 通知主循环有数据到达 */
}

/* 非阻塞读取：安全地从缓冲区取数据 */
int uart_dma_read(uint8_t *out, uint16_t max_len) {
    uint16_t remaining = __HAL_DMA_GET_COUNTER(&hdma_usart1_rx);
    uint16_t written = RX_BUF_SIZE - remaining;

    uint16_t avail = written - cpu_tail;
    if (avail == 0 || avail > max_len) return 0;

    uint16_t start = cpu_tail % RX_BUF_SIZE;
    for (uint16_t i = 0; i < avail; i++) {
        out[i] = dma_rx_buf[(start + i) % RX_BUF_SIZE];
    }
    cpu_tail += avail;
    new_data = 0;
    return (int)avail;
}
